SELECT [Sales Shipment Line].[Sell-to Customer No_], Customer.Name, [Sales Shipment Line].Type, [Sales Shipment Line].[Document No_] AS SpedRegNr, [DDT_Picking Header].[Posted No_] AS DDTFinalNO, [Sales Shipment Line].[DDT No_] AS DDTTempNO, [Sales Shipment Line].[Line No_] AS SpedRegLi, [Sales Shipment Line].[Order No_], [Sales Line].[Line No_] AS OrdineRiga, Val([sales shipment line.Quantity]) AS SpedRegQTY, [Sales Shipment Line].[VAT Bus_ Posting Group] AS SpedRegCateBusIVaCLie, [Sales Shipment Line].[VAT Prod_ Posting Group] AS SpedRegCatRegArtIva, [Sales Line].[VAT Bus_ Posting Group] AS RigaOrdineCateIvaClient, [Sales Line].[VAT Prod_ Posting Group] AS RigaOrdineCatIvaArticiolo, [Sales Line].[VAT Identifier] AS RigaOrdineCodiceIva
FROM (([Sales Shipment Line] LEFT JOIN Customer ON [Sales Shipment Line].[Sell-to Customer No_] = Customer.No_) LEFT JOIN [DDT_Picking Header] ON [Sales Shipment Line].[DDT No_] = [DDT_Picking Header].No_) LEFT JOIN [Sales Line] ON ([Sales Shipment Line].[Order Line No_] = [Sales Line].[Line No_]) AND ([Sales Shipment Line].[Order No_] = [Sales Line].[Document No_])
WHERE ((([Sales Shipment Line].[Document No_])="SPR-19/01021" Or ([Sales Shipment Line].[Document No_])="SPR-19/01237" Or ([Sales Shipment Line].[Document No_])="SPR-19/01238" Or ([Sales Shipment Line].[Document No_])="SPR-19/01889" Or ([Sales Shipment Line].[Document No_])="SPR-19/01890" Or ([Sales Shipment Line].[Document No_])="SPR-19/03153" Or ([Sales Shipment Line].[Document No_])="SPR-19/03154" Or ([Sales Shipment Line].[Document No_])="SPR-19/03344" Or ([Sales Shipment Line].[Document No_])="SPR-19/04370" Or ([Sales Shipment Line].[Document No_])="SPR-19/04371"));

